import EditObject from './EditObject'
import NoneSelected from './NoneSelected'

function Sidebar({ newObject }) {
    return (
        <aside className="sidebar">
            <button onClick={newObject}>Add object</button>
            <EditObject></EditObject> <NoneSelected></NoneSelected>
        </aside>
    );
}

export default Sidebar;
